A provider-agnostic resilience utility used to wrap every PDAX call (Task 4) and reusable by Phase 5 worker jobs. Exponential backoff + full jitter + per-attempt timeout + a simple circuit breaker.

**Files:**
- Create: `src/lib/retry.ts`
- Test: `tests/lib/retry.test.ts`

**Interfaces:**
- Consumes: nothing from earlier phases (intentionally dependency-free so it can wrap anything).
- Produces (consumed by Task 4 and Phase 5):
  ```typescript
  export class TimeoutError extends Error {}            // thrown when a single attempt exceeds timeoutMs
  export type RetryOptions = {
    retries?: number;        // max retry attempts AFTER the first try (default 3)
    baseMs?: number;         // backoff base (default 200)
    maxMs?: number;          // backoff cap (default 5000)
    timeoutMs?: number;      // per-attempt timeout (default 10000); 0 disables
    jitter?: boolean;        // full jitter on the delay (default true)
    isRetryable?: (err: unknown) => boolean; // default: always retry
    sleepImpl?: (ms: number) => Promise<void>; // injectable for tests (default real setTimeout)
    randomImpl?: () => number;                 // injectable for tests (default Math.random)
  };
  export function withTimeout<T>(p: Promise<T>, ms: number): Promise<T>;
  export function withRetry<T>(fn: (attempt: number) => Promise<T>, opts?: RetryOptions): Promise<T>;
  export type CircuitBreakerOptions = { failureThreshold?: number; resetMs?: number; nowImpl?: () => number };
  export type CircuitState = "closed" | "open" | "half-open";
  export class CircuitBreaker {
    constructor(opts?: CircuitBreakerOptions);
    get state(): CircuitState;
    exec<T>(fn: () => Promise<T>): Promise<T>; // throws CircuitOpenError while open
  }
  export class CircuitOpenError extends Error {}
  ```

- [ ] **Step 1: Write the failing tests**

```typescript
// tests/lib/retry.test.ts
import { describe, it, expect, vi } from "vitest";
import {
  withRetry,
  withTimeout,
  TimeoutError,
  CircuitBreaker,
  CircuitOpenError,
} from "@/lib/retry";

const noSleep = (_ms: number) => Promise.resolve();

describe("withRetry", () => {
  it("succeeds after N transient failures", async () => {
    let calls = 0;
    const fn = vi.fn(async () => {
      calls += 1;
      if (calls < 3) throw new Error("transient");
      return "ok";
    });
    const result = await withRetry(fn, { retries: 5, baseMs: 1, sleepImpl: noSleep, randomImpl: () => 0 });
    expect(result).toBe("ok");
    expect(calls).toBe(3);
  });

  it("gives up after max retries and throws the last error", async () => {
    const fn = vi.fn(async () => {
      throw new Error("boom");
    });
    await expect(
      withRetry(fn, { retries: 2, baseMs: 1, sleepImpl: noSleep, randomImpl: () => 0 }),
    ).rejects.toThrow("boom");
    expect(fn).toHaveBeenCalledTimes(3); // 1 initial + 2 retries
  });

  it("respects isRetryable=false (no retry on non-retryable errors)", async () => {
    const fn = vi.fn(async () => {
      throw new Error("fatal");
    });
    await expect(
      withRetry(fn, { retries: 5, baseMs: 1, sleepImpl: noSleep, isRetryable: () => false }),
    ).rejects.toThrow("fatal");
    expect(fn).toHaveBeenCalledTimes(1);
  });

  it("times out a hung attempt with TimeoutError", async () => {
    const hung = () => new Promise<string>(() => {});
    await expect(
      withRetry(hung, { retries: 0, timeoutMs: 10, sleepImpl: noSleep }),
    ).rejects.toBeInstanceOf(TimeoutError);
  });

  it("backoff is exponential and capped by maxMs", async () => {
    const delays: number[] = [];
    const fn = vi.fn(async () => {
      throw new Error("x");
    });
    await expect(
      withRetry(fn, {
        retries: 4,
        baseMs: 100,
        maxMs: 350,
        jitter: false,
        sleepImpl: (ms) => {
          delays.push(ms);
          return Promise.resolve();
        },
      }),
    ).rejects.toThrow();
    // 100, 200, 350 (capped), 350 (capped) — one delay per retry
    expect(delays).toEqual([100, 200, 350, 350]);
  });
});

describe("withTimeout", () => {
  it("resolves when the promise wins the race", async () => {
    await expect(withTimeout(Promise.resolve(42), 1000)).resolves.toBe(42);
  });
  it("rejects with TimeoutError when the timeout wins", async () => {
    await expect(withTimeout(new Promise(() => {}), 10)).rejects.toBeInstanceOf(TimeoutError);
  });
});

describe("CircuitBreaker", () => {
  it("opens after the failure threshold then rejects fast", async () => {
    let now = 0;
    const cb = new CircuitBreaker({ failureThreshold: 2, resetMs: 1000, nowImpl: () => now });
    const boom = () => Promise.reject(new Error("down"));
    await expect(cb.exec(boom)).rejects.toThrow("down");
    await expect(cb.exec(boom)).rejects.toThrow("down");
    expect(cb.state).toBe("open");
    // while open, the wrapped fn is NOT called — we get CircuitOpenError
    const spy = vi.fn(() => Promise.resolve("should-not-run"));
    await expect(cb.exec(spy)).rejects.toBeInstanceOf(CircuitOpenError);
    expect(spy).not.toHaveBeenCalled();
  });

  it("half-opens after resetMs and closes on a success", async () => {
    let now = 0;
    const cb = new CircuitBreaker({ failureThreshold: 1, resetMs: 1000, nowImpl: () => now });
    await expect(cb.exec(() => Promise.reject(new Error("down")))).rejects.toThrow("down");
    expect(cb.state).toBe("open");
    now = 1500; // past resetMs → half-open allows one trial
    await expect(cb.exec(() => Promise.resolve("ok"))).resolves.toBe("ok");
    expect(cb.state).toBe("closed");
  });
});
```

